program.STSource:
(* start weighing process for material A *)

if  re (Start_process) or re (new_material_demand) then
	set (weight_empty);
	set (valve_a_closed);
	set (valve_b_closed);
	reset (valve_b_open);
end_if;

(* creating internal pulse *)

sec:=%S6;
ms_100:=%s5;
ms_10:=%s4;

(* opening valve A *)

if re (weight_empty) then
	set(valve_a_open);
	reset (valve_a_closed);
	reset (ready_to_mix);
	reset (weighing_a_done);
end_if;

(* filling weight till demandet value *)

if valve_a_open and re (sec)and Weighing_material_A<=material_a_value then
	inc_int (Weighing_Material_A);
	reset (weight_empty);
end_if;


(* close valve A if demandet value reached *)
(* set internal bit flapp A => for operator screen *)

if weighing_material_a=material_a_value then
	reset (valve_a_open);
	set (valve_a_closed);
	set (weighing_a_done);
	Flapp_a:=true;
		if flapp_a then 
			weighing_material_a:=0;
			set (material_a_in);
		end_if;		
end_if;

if fe (mixing_done) then
	reset (material_a_in);
	reset (Material_b_in);
end_if;

(* delay time for flapp open *)

Flapp (IN := Flapp_A or Flapp_b,
    PT := t#5s,
    Q => Flapp_open);
